class Solution:
    def countPoints(self, points, queries):
        res = []
        for cx, cy, r in queries:
            rr = r * r
            cnt = 0
            for px, py in points:
                dx = px - cx
                dy = py - cy
                if dx * dx + dy * dy <= rr:
                    cnt += 1
            res.append(cnt)
        return res

