class Solution:
    def countPoints(self, points, queries):
        ans = []
        for cx, cy, r in queries:
            rr = r * r
            c = 0
            for px, py in points:
                if (px - cx) ** 2 + (py - cy) ** 2 <= rr:
                    c += 1
            ans.append(c)
        return ans

