var countPoints = function(points, queries) {
    const ans = [];
    for (const [cx, cy, r] of queries) {
        const rr = r * r;
        let c = 0;
        for (const [px, py] of points) {
            const dx = px - cx, dy = py - cy;
            if (dx * dx + dy * dy <= rr) c++;
        }
        ans.push(c);
    }
    return ans;
};
